SourceCode.Declaration:
/// <summary>
/// Site import
/// </summary>
public class ETG_Acu_InventSiteImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_InventSiteImport  inventSiteImport;

    inventSiteImport = ETG_Acu_InventSiteImport::construct();

    if (inventSiteImport.prompt())
    {
        inventSiteImport.runOperation();
    }
}

public static ETG_Acu_InventSiteImport construct()
{
    return new ETG_Acu_InventSiteImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    InventOperationalSiteV2Entity   site;

    InventSiteId    siteId;

    siteId = conpeek(_con, 1);

    select firstonly forupdate site
        where site.SiteId == siteId;

    if (!site)
    {
        site.SiteId         = conpeek(_con, 1);
        site.SiteName       = conpeek(_con, 2);
        site.SiteTimezone   = conpeek(_con, 3);
        site.insert();
    }
    else
    {
        site.SiteName       = conpeek(_con, 2);
        site.SiteTimezone   = conpeek(_con, 3);
        site.update();
    }
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpSite";

    return ret;
}
